<script setup lang="ts">import{ref}from'vue';import{useRouter}from'vue-router';import{useAuthStore}from'../stores/auth';const username=ref('');const password=ref('');const error=ref('');const auth=useAuthStore(),router=useRouter();async function submit(){try{await auth.login(username.value,password.value);router.push('/')}catch(e:any){error.value=e.message}}</script>
<template><div class="login card"><h1>AI 教育智能体</h1><p>请使用教师、学生、家长或管理员账号登录。</p><form @submit.prevent="submit"><label>用户名</label><input v-model="username" required><label>密码</label><input v-model="password" type="password" required><p class="error">{{error}}</p><button>登录</button> <router-link to="/register">注册学生账号</router-link></form></div></template>
